/**
 * Normalizes movie poster URLs from OMDb (higher resolution when available).
 */
export function upgradePoster(movie) {
  const poster = movie?.poster || movie?.Poster;
  if (poster && typeof poster === "string" && poster.includes("SX300")) {
    return {
      ...movie,
      poster: poster.replace("SX300", "SX1000"),
      title: movie.title || movie.Title,
      id: movie.id || movie.imdbID,
    };
  }
  return {
    ...movie,
    title: movie.title || movie.Title,
    id: movie.id || movie.imdbID,
  };
}
